code = """import pandas as pd
import json
# data from previous query
records = var_call_wxdNMfsPG0tsNqdDIsCMG6Rh
df = pd.DataFrame(records)
# clean whitespace
for col in ['caseid__c','oldvalue__c','newvalue__c','createddate']:
    if col in df.columns:
        df[col] = df[col].astype(str).str.strip()
# treat 'None' as None
df['oldvalue__c'] = df['oldvalue__c'].replace({'None': None})
df['newvalue__c'] = df['newvalue__c'].replace({'None': None})
# considered timeframe already filtered by query
# Agents who handled >0 cases: appear as newvalue__c not None; count distinct cases per agent
handled = df[df['newvalue__c'].notna()].groupby('newvalue__c')['caseid__c'].nunique().rename('handled_cases').reset_index()
handled = handled.rename(columns={'newvalue__c':'agent_id'})
# transfers from agent: oldvalue__c equals agent_id and oldvalue__c not None
transfers = df[df['oldvalue__c'].notna()].groupby('oldvalue__c').size().rename('transfer_count').reset_index()
transfers = transfers.rename(columns={'oldvalue__c':'agent_id'})
# merge
merged = pd.merge(handled, transfers, on='agent_id', how='left')
merged['transfer_count'] = merged['transfer_count'].fillna(0).astype(int)
# filter agents who handled >0 (handled already ensures >0)
# find agent with minimum transfer_count
min_tc = merged['transfer_count'].min()
cands = merged[merged['transfer_count']==min_tc].sort_values('agent_id')
# choose first candidate
if not cands.empty:
    result_agent = cands.iloc[0]['agent_id']
else:
    result_agent = None
out = json.dumps(result_agent)
print("__RESULT__:")
print(out)"""

